mapper.select:
SELECT BOARD_ID AS boardId, BOARD_TITLE AS boardTitle, BOARD_CONTENT AS boardContent, CREATE_DATE AS createDate, MODIFY_DATE AS modifyDate, DELETE_DATE AS deleteDate, VIEW_COUNT AS viewCount, STOCK_ID AS stockId, BOARD_TYPE AS boardType, USER_ID AS userId FROM BOARD WHERE DELETE_DATE IS NULL
AND BOARD_TYPE = #{boardType}
AND STOCK_ID = #{stockId}
ORDER BY CREATE_DATE DESC OFFSET #{offset} ROWS FETCH NEXT #{size} ROWS ONLY
